mapper.select:
SELECT s.log_id, s.user_type, s.user_id, s.operation, s.operation_detail, s.ip_address, s.create_time,
    (SELECT t.real_name FROM teacher t WHERE t.teacher_id = s.user_id) AS user_name
FROM system_log s
WHERE s.user_type = 2 AND s.user_id = #{userId}
ORDER BY s.create_time DESC
LIMIT #{limit}
